Here's how to implement all three requirements:

## 1. Custom "Cancel" Back Button (in your page XAML)

```xml
<!-- EditProductPage.xaml -->
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.EditProductPage">

    <Shell.BackButtonBehavior>
        <BackButtonBehavior TextOverride="Cancel"
                           Command="{Binding CancelCommand}" />
    </Shell.BackButtonBehavior>

    <!-- page content -->
</ContentPage>
```

## 2. ViewModel with Cancel Command

```csharp
public partial class EditProductViewModel : ObservableObject
{
    [ObservableProperty]
    private bool hasUnsavedChanges;

    [RelayCommand]
    private async Task Cancel()
    {
        if (HasUnsavedChanges)
        {
            bool discard = await Shell.Current.DisplayAlert(
                "Unsaved Changes",
                "Discard changes and go back?",
                "Discard", "Stay");

            if (!discard) return; // cancel navigation
        }

        await Shell.Current.GoToAsync("..");
    }
}
```

## 3. Guard the System Back Navigation (hardware/gesture)

Override `OnNavigating` in `AppShell.xaml.cs` to catch swipe-back or hardware back:

```csharp
public partial class AppShell : Shell
{
    public AppShell()
    {
        InitializeComponent();
        Routing.RegisterRoute("editproduct", typeof(EditProductPage));
    }

    protected override async void OnNavigating(ShellNavigatingEventArgs args)
    {
        base.OnNavigating(args);

        // Only intercept back (Pop) navigation from EditProductPage
        if (args.Source == ShellNavigationSource.Pop
            && CurrentPage is EditProductPage page
            && page.BindingContext is EditProductViewModel vm
            && vm.HasUnsavedChanges)
        {
            var deferral = args.GetDeferral();

            bool discard = await page.DisplayAlert(
                "Unsaved Changes",
                "Discard changes and go back?",
                "Discard", "Stay");

            if (!discard)
                args.Cancel();

            deferral.Complete();
        }
    }
}
```

**Key points:**
- `GetDeferral()` is required for async checks — without it the navigation completes before your dialog returns.
- `BackButtonBehavior.Command` replaces the default back action, so your command controls navigation manually via `GoToAsync("..")`.
- The `OnNavigating` guard catches system back (swipe/hardware button) that bypasses `BackButtonBehavior`.
